#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long LL;
inline int read()
{
	int res(0);char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int Inf=0x3f3f3f3f;const LL INF=0x3f3f3f3f3f3f3f3fll;int n,m,idx[1010];
namespace MCMF
{
	const int N=2010,M=1e6+10;int head[N],des[M],nxt[M],cgt=1;LL cap[M],val[M];
	inline void ins(const int &x,const int &y,const int &c,const int &w)
	{
		nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;val[cgt]=w;
		nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;val[cgt]=-w;
	}
	int que[20000010],H,T;LL dis[N],mnc;int s,t,S;bool inq[N];
	inline bool spfa()
	{
		memset(dis,0x3f,(S+2)<<3);dis[que[H=T=0]=s]=0;
		while(H<=T)
		{
			int u=que[H++];inq[u]=false;
			grep(u,i){int v=des[i];if(cap[i]&&dis[v]>dis[u]+val[i]){dis[v]=dis[u]+val[i];if(!inq[v])inq[que[++T]=v]=true;}}
		}
		return dis[t]!=INF;
	}
	inline LL dfs(const int &u=s,LL in=INF)
	{
		if(u==t)return in;LL out=0;inq[u]=true;grep(u,i)
		{
			int v=des[i];if(cap[i]&&!inq[v]&&dis[v]==dis[u]+val[i])
			{
				LL tmp=dfs(v,cap[i]<in?cap[i]:in);mnc+=tmp*val[i];
				cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
			}
		}
		if(!out)dis[u]=INF;inq[u]=false;return out;
	}
	inline LL dinic(){LL res=0;while(spfa())res+=dfs();return res;}
}
using MCMF::ins;using MCMF::s;using MCMF::t;using MCMF::S;using MCMF::dinic;
int main()
{
	n=read();m=read();s=++S;t=++S;ins(s,idx[1]=++S,Inf,0);
	rep(1,n,i)ins(idx[i],idx[i+1]=++S,Inf-read(),0);ins(idx[n+1],t,Inf,0);
	rep(1,m,i){int l=read(),r=read()+1;ins(idx[l],idx[r],Inf,read());}
	dinic();printf("%lld\n",MCMF::mnc);
}
